import{_ as t,o,c as r,a0 as a}from"./chunks/framework.CWk8AOcY.js";const i="/assets/server-log.DSY5175U.png",s="/assets/gui-options.B9GCdRvn.png",n="/assets/server-options-local.DHoF9pMU.png",l="/assets/server-options-remote.BJ7Uu7Ex.png",c="/assets/sound-options.DEAYT-Qx.png",d="/assets/about-box.B8bog4o5.png",y=JSON.parse('{"title":"Configuring the GUI","description":"","frontmatter":{},"headers":[],"relativePath":"articles/gui-configuration.md","filePath":"articles/gui-configuration.md"}'),h={name:"articles/gui-configuration.md"};function u(g,e,p,f,b,m){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="configuring-the-gui" tabindex="-1">Configuring the GUI <a class="header-anchor" href="#configuring-the-gui" aria-label="Permalink to &quot;Configuring the GUI&quot;">​</a></h1><p>This guide covers the dialogs used to configure the GUI, the local server, debugging features, and sound.</p><h2 id="local-server-log" tabindex="-1">Local Server Log <a class="header-anchor" href="#local-server-log" aria-label="Permalink to &quot;Local Server Log&quot;">​</a></h2><p>The GUI provides a built-in server log viewer when running a local server:</p><p><img src="'+i+'" alt="Local Server Log"></p><p>Use it to monitor server activity, debug connection issues, and follow battle events in real time. Log viewing is only available for local servers, not remote ones.</p><h2 id="gui-options" tabindex="-1">GUI Options <a class="header-anchor" href="#gui-options" aria-label="Permalink to &quot;GUI Options&quot;">​</a></h2><p>The <strong>GUI Options</strong> dialog controls language, UI scaling, console limits, and other general GUI preferences:</p><p><img src="'+s+'" alt="GUI Options"></p><p>You can use it to:</p><ul><li>change the GUI language</li><li>adjust UI scaling for high-resolution displays</li><li>set the maximum number of characters retained in a console</li><li>set the boot timeout in seconds</li></ul><h3 id="tank-color-mode" tabindex="-1">Tank color mode <a class="header-anchor" href="#tank-color-mode" aria-label="Permalink to &quot;Tank color mode&quot;">​</a></h3><p>The <strong>Tank color mode</strong> group controls how tank colors are resolved during rendering:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Mode</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Bot Colors</strong></td><td style="text-align:left;">Bot-defined colors are used and can change freely during the battle.</td></tr><tr><td style="text-align:left;"><strong>Bot Colors (Once)</strong></td><td style="text-align:left;">The first color reported by each bot component is locked for the entire battle.</td></tr><tr><td style="text-align:left;"><strong>Default Colors</strong></td><td style="text-align:left;">Bot-defined colors are ignored and all tanks use the standard default colors.</td></tr><tr><td style="text-align:left;"><strong>Bot Colors (Debug Only)</strong></td><td style="text-align:left;">Bot-defined colors are shown only while debug mode is active.</td></tr></tbody></table><p>For the underlying <code>gui.properties</code> file, see <a href="./configuration-files.html">Configuration files</a>.</p><h2 id="server-options" tabindex="-1">Server Options <a class="header-anchor" href="#server-options" aria-label="Permalink to &quot;Server Options&quot;">​</a></h2><p>The <strong>Server Options</strong> dialog lets you configure the server used for battles. At the top of the dialog, the GUI shows the URL of the currently selected server.</p><h3 id="local-server" tabindex="-1">Local Server <a class="header-anchor" href="#local-server" aria-label="Permalink to &quot;Local Server&quot;">​</a></h3><p>By default, Robocode Tank Royale uses a local server that starts automatically on localhost. You can configure:</p><ul><li>the server port</li><li>server authentication using secrets</li><li>security settings that restrict access</li></ul><p>When server secrets are enabled, all clients and bots must authenticate with the correct secret to join. Bots can provide the secret through either:</p><ul><li>the Bot API</li><li>the <code>SERVER_SECRET</code> environment variable</li></ul><p><img src="'+n+'" alt="Local Server Options"></p><h4 id="local-server-secrets" tabindex="-1">Local Server Secrets <a class="header-anchor" href="#local-server-secrets" aria-label="Permalink to &quot;Local Server Secrets&quot;">​</a></h4><p>Secret authentication is disabled by default (<code>enable-server-secrets=false</code>). Enable it in the Server Options dialog or edit <code>server.properties</code> directly when you need to restrict access to the server.</p><p>When secrets are enabled, <code>server.properties</code> contains the generated keys that bots and controllers must present to connect.</p><p>You can change the secrets by editing the file manually or regenerating them through the Server Options dialog.</p><p>For the full <code>server.properties</code> reference, see <a href="./configuration-files.html">Configuration files</a>.</p><h3 id="remote-server" tabindex="-1">Remote Server <a class="header-anchor" href="#remote-server" aria-label="Permalink to &quot;Remote Server&quot;">​</a></h3><p>You can also connect the GUI to a remote server. Remote servers are expected to run externally and are therefore not started automatically when you launch a battle.</p><p>To connect to a remote server:</p><ol><li>Enter the server URL in WebSocket format, such as <code>ws://hostname:port</code></li><li>Provide the controller and bot secrets configured on that server</li><li>Click <strong>Apply</strong></li></ol><p>Without the correct secrets, neither the GUI nor bots can authenticate and connect to the remote server.</p><p><img src="'+l+'" alt="Remote Server Options"></p><h2 id="debug-options" tabindex="-1">Debug Options <a class="header-anchor" href="#debug-options" aria-label="Permalink to &quot;Debug Options&quot;">​</a></h2><p>The <strong>Debug Options</strong> dialog contains development and testing features:</p><ul><li><strong>Initial Bot Position</strong> allows bots to specify their starting position either through the <code>initialPosition</code> field in their JSON config file or programmatically through the <code>BotInfo</code> class</li></ul><p>This option is meant for debugging only. In normal play, bots are not allowed to choose their starting position.</p><h2 id="sound-options" tabindex="-1">Sound Options <a class="header-anchor" href="#sound-options" aria-label="Permalink to &quot;Sound Options&quot;">​</a></h2><p>The <strong>Sound Options</strong> dialog controls the game audio:</p><ul><li>a global sound toggle</li><li>individual toggles for each sound effect type</li><li>a volume control</li></ul><p><img src="'+c+'" alt="Sound Options"></p><p>For installing the optional sound files, see <a href="./installing-sounds.html">Installing sounds</a>.</p><h2 id="about-box" tabindex="-1">About box <a class="header-anchor" href="#about-box" aria-label="Permalink to &quot;About box&quot;">​</a></h2><p>The About dialog shows system and support information:</p><ul><li>Robocode Tank Royale version number</li><li>Java runtime version and vendor details</li><li>a link for reporting <a href="https://github.com/robocode-dev/tank-royale/issues/new/choose" title="Create new issue" target="_blank" rel="noreferrer">new issue</a>s on GitHub</li><li>recognition of project <a href="https://github.com/robocode-dev/tank-royale/graphs/contributors" title="Contributors" target="_blank" rel="noreferrer">contributors</a></li></ul><p>This information is useful when reporting bugs or compatibility issues.</p><p><img src="'+d+'" alt="About box"></p>',48)])])}const x=t(h,[["render",u]]);export{y as __pageData,x as default};
